// ─── Typed Client ──────────────────────────────────────────────────

export interface TypedClient {
  /** List content entries of a given type */
  getEntries<K extends ContentTypeName>(
    type: K,
    options?: QueryOptions,
  ): Promise<ContentTypeMap[K][]>

  /** Get a single content entry by UUID */
  getEntry<K extends ContentTypeName>(
    type: K,
    id: string,
  ): Promise<ContentTypeMap[K] | null>

  /** Resolve a Drupal path to a typed content node */
  getEntryByPath(path: string): Promise<ContentNode | null>

  /** Escape hatch: run a raw GraphQL query */
  raw<T = any>(query: string, variables?: Record<string, any>): Promise<T>
}


// ─── Factory ───────────────────────────────────────────────────────

export function createTypedClient(client: DecoupledClient): TypedClient {
  return {
    async getEntries(type, options) {
      const config = QUERIES[type]
      const data = await client.query(config.list, options)
      // Extract nodes from the connection response
      const key = Object.keys(data)[0]
      return data[key]?.nodes ?? []
    },
    async getEntry(type, id) {
      const config = QUERIES[type]
      const data = await client.query(config.single, { id })
      const key = Object.keys(data)[0]
      return data[key] ?? null
    },
    async getEntryByPath(path) {
      return client.queryByPath(path, ROUTE_QUERY)
    },
    async raw(query, variables) {
      return client.query(query, variables)
    },
  }
}
